import{_ as i,o as l,c as a,ag as o}from"./chunks/framework.BZohXCq9.js";const h=JSON.parse('{"title":"UI 模块架构","description":"","frontmatter":{},"headers":[],"relativePath":"ui.md","filePath":"ui.md","lastUpdated":1775493867000}'),d={name:"ui.md"};function t(r,e,c,n,u,s){return l(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="ui-模块架构" tabindex="-1">UI 模块架构 <a class="header-anchor" href="#ui-模块架构" aria-label="Permalink to &quot;UI 模块架构&quot;">​</a></h1><p><code>0.2.0</code> 的 UI 不再被理解成“唯一的一套桌面界面”，而是两条并行推进的方向：</p><ul><li><code>modlink_ui_qt_widgets</code>：当前主桌面宿主使用的 Qt Widgets UI 包</li><li><code>modlink_ui_qt_qml</code>：新的 QML UI 包</li></ul><p>同时，<code>modlink_server</code> 建立的是另一条 host 边界，用于后续 HTML / Web UI，而不是再去扩展 Qt Widgets 的职责。</p><h2 id="ui-最该依赖什么" tabindex="-1">UI 最该依赖什么 <a class="header-anchor" href="#ui-最该依赖什么" aria-label="Permalink to &quot;UI 最该依赖什么&quot;">​</a></h2><p>写展示页面时，最值得先依赖的是这些稳定字段：</p><ul><li><code>stream_id</code></li><li><code>payload_type</code></li><li><code>data.shape</code></li><li><code>channel_names</code></li><li><code>metadata[&quot;unit&quot;]</code></li><li><code>display_name</code></li></ul><p>如果这些信息已经稳定，UI 通常也会稳定。UI 最好消费的是统一流模型，而不是某个具体设备自己的协议细节。</p><h2 id="_0-2-0-的三条表现层方向" tabindex="-1">0.2.0 的三条表现层方向 <a class="header-anchor" href="#_0-2-0-的三条表现层方向" aria-label="Permalink to &quot;0.2.0 的三条表现层方向&quot;">​</a></h2><h3 id="modlink-ui-qt-widgets" tabindex="-1"><code>modlink_ui_qt_widgets</code> <a class="header-anchor" href="#modlink-ui-qt-widgets" aria-label="Permalink to &quot;`modlink_ui_qt_widgets`&quot;">​</a></h3><p>这是当前主桌面宿主 <code>modlink_studio</code> 使用的 UI 包。它承担：</p><ul><li>主窗口和页面结构</li><li>设备页、设置页、采集面板</li><li>现有 Widgets 预览链路</li></ul><p><code>0.2.0</code> 里它仍然会继续保留，不作为被替代或被删除的旧路径。</p><h3 id="modlink-ui-qt-qml" tabindex="-1"><code>modlink_ui_qt_qml</code> <a class="header-anchor" href="#modlink-ui-qt-qml" aria-label="Permalink to &quot;`modlink_ui_qt_qml`&quot;">​</a></h3><p>这是 <code>0.2.0</code> 首次明确推进的新桌面 UI 方向。它当前承担：</p><ul><li>QML 页面结构</li><li>preview controller / store / pipeline</li><li>更适合继续扩展的预览和界面组织方式</li></ul><p>推进这条线的原因不是“多做一个界面”，而是随着实时预览类型、界面层级和后续交互复杂度增加，Qt Widgets 在表达能力和演进空间上的局限越来越明显。</p><h3 id="modlink-server" tabindex="-1"><code>modlink_server</code> <a class="header-anchor" href="#modlink-server" aria-label="Permalink to &quot;`modlink_server`&quot;">​</a></h3><p><code>modlink_server</code> 不是另一套桌面 UI，但它确实属于 <code>0.2.0</code> 的 new UI / host 方向。</p><p>它当前的意义是：</p><ul><li>把 backend 暴露为明确的服务宿主</li><li>固定 <code>HTTP + SSE + WebSocket</code> 三条 wire contract</li><li>为后续 HTML / Web UI 提前建立 host 边界</li></ul><p>因此当文档里提到 <code>0.2.0</code> 的 new UI 时，实际上包含两条方向：</p><ul><li>QML 桌面 UI</li><li>FastAPI 服务化 host</li></ul><h2 id="一个合理的-ui-工作顺序" tabindex="-1">一个合理的 UI 工作顺序 <a class="header-anchor" href="#一个合理的-ui-工作顺序" aria-label="Permalink to &quot;一个合理的 UI 工作顺序&quot;">​</a></h2><ol><li>先拿到 <code>StreamDescriptor</code></li><li>再决定这个流应该怎么画</li><li>再订阅对应 <code>stream_id</code></li><li>最后根据 <code>FrameEnvelope.data</code> 的 shape 解释实时数据</li></ol><p>也就是说，UI 不应该在收到 frame 时临时猜“这是不是 EEG”“这是不是三轴加速度计”；这些信息更适合来自 descriptor。</p><h2 id="为什么-ui-不该直接依赖设备协议" tabindex="-1">为什么 UI 不该直接依赖设备协议 <a class="header-anchor" href="#为什么-ui-不该直接依赖设备协议" aria-label="Permalink to &quot;为什么 UI 不该直接依赖设备协议&quot;">​</a></h2><p>一旦 UI 直接依赖某个设备 SDK 的特殊字段，后面就很难复用。</p><p>例如：</p><ul><li>如果 UI 直接判断“这是 Ganglion，所以应该有 4 个 EEG 通道”</li><li>那它就无法自然复用到另一个 EEG 设备</li></ul><p>更合理的方式是：</p><ul><li>UI 只读 <code>StreamDescriptor.channel_names</code></li><li>UI 只读 <code>payload_type</code></li><li>UI 只解释统一的 <code>FrameEnvelope.data</code></li></ul><p>这样换一个设备，只要 descriptor 和 data shape 还守同一套约定，UI 就能继续工作。</p><h2 id="ui-和-core-的边界" tabindex="-1">UI 和 Core 的边界 <a class="header-anchor" href="#ui-和-core-的边界" aria-label="Permalink to &quot;UI 和 Core 的边界&quot;">​</a></h2><p>UI 通常不需要知道：</p><ul><li>driver 跑在哪条线程上</li><li>设备怎么搜索</li><li>设备怎么连接</li><li>流是 callback 还是 loop 驱动的</li></ul><p>UI 真正需要知道的是：</p><ul><li>这个流叫什么</li><li>这个流怎么解释</li><li>什么时候有新数据</li></ul><p>因此对 UI 来说，Core 更像“稳定的流提供者”；Qt bridge 的职责是把 runtime 安全地接回 UI 主线程，而不是在 bridge 里定义新的后端语义。</p><h2 id="推荐阅读" tabindex="-1">推荐阅读 <a class="header-anchor" href="#推荐阅读" aria-label="Permalink to &quot;推荐阅读&quot;">​</a></h2><ul><li>接设备：看 <a href="/sdk">SDK</a></li><li>看运行时边界：看 <a href="/core">Core</a></li><li>看宿主装配：看 <a href="/app">App</a></li><li>看服务化接口：看 <a href="/server-api">服务端 API 手册</a></li></ul>',41)])])}const m=i(d,[["render",t]]);export{h as __pageData,m as default};
